    _gravity = value;
    _updateFormula();
    notifyListeners();
    _fetchFromBackend();
  }

  void _updateFormula() {
    _customFormula =
        'y = x * tan(${_angle.toStringAsFixed(1)}°) - (${_gravity.toStringAsFixed(1)} * x²) / (2 * ${_velocity.toStringAsFixed(1)}² * cos²(${_angle.toStringAsFixed(1)}°))';
